const Q_COMMERCE_2002=[{"id": "objective>Commerce>2002>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important factor that delayed the development of commerce in Nigeria was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the inefficient means of communication</div>", "<div style=\"font-family:Cambria;font-size:17px;\">that there were few entrepreneurs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the unavailability of  infrastructural  facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">that there were few developed markets</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The factors that affect the growth of commerce are: <br/> - insufficient capital <br/> - political instability <br/> - low savings <br/> - lack of adequate commercial facilities <br/> - absence of well developed market <br/> - poor transportation and communication system.</div>", "topic": "TRADE ( 2) : FOREIGN TRADE"}, {"id": "objective>Commerce>2002>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary production has to do with changing the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shape of raw materials through construction operation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">physical form of raw materials into finished goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unity of raw materials by an engineering process</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nature of raw materials through manufacturing processes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary production refers to the process of transforming raw materials into finished goods. This involves changing the physical form of raw materials. For example, turning iron ore into steel or wheat into flour. Therefore, the correct answer is 'physical form of raw materials into finished goods'.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2002>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major responsibility of an entrepreneur is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">employing all factors of production in the business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coordinating and determining the proportion of what to produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">planning and organizing all activities in the business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">directing and controlling all the affairs of the business</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This encompasses the core entrepreneurial activity of assembling and integrating the necessary resources to establish and operate a business, which is indeed a fundamental entrepreneurial function.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : BUSINESS RESOURCES"}, {"id": "objective>Commerce>2002>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best describes the scope of commerce?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all forms of commercial exchange and the manufacturing industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buying and selling and the construction industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all occupational exchanges relating to industries and commercial activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buying and selling as well as the extraction of the natural resources</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The scope of commerce may be seen as embracing the totality of all activities which ensure the distribution and exchange of goods and services for the satisfaction of the people. It embraces trade and aids to trade.</div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>2002>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Capital as a factor of production can be used as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">money that is regarded as assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">goods that are useful in business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">input for further production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">service that provides satisfaction</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Accountant's definition of capital <br/> - Money used for and required in carrying out any business venture or transaction. Therefore, money is regarded as capital to the accountant. <br/> -  The monetary value of the excess of business assets over its liabilities i.e.  Capital = Total assets - Total liabilities. Therefore, capital is the net worth of the business. <br/>  <br/> Economist's definition of capital <br/> The man-made resources or assets that are used for the production of more wealth. Thus, Economist regards capital as a factor of production. <br/>  <br/> Layman's definition of capital <br/> The amount of money he has invested in his business i.e. the money used to start up a business.</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2002>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The agency that currently oversees the privatization and commercialization process in Nigeria is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Securities and Exchange Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Technical Committee on privatization and Commercialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Stock Exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bureau of Public Enterprises</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bureau of Public Enterprises is governmental agency which oversees all privatization and commercialization process in Nigeria.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES"}, {"id": "objective>Commerce>2002>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Okeze contracted to sell TV sets to Ojo. Unknown to them, the sets were stolen in transit. This contract may be on the grounds of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bankruptcy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frustration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fraudulence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">breach of contract</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A contract is frustration when it is an act of God i.e device to set aside contracts where an unforeseen event either renders contractual obligations impossible, or radically changes the party's principal purpose for entering into the contract. E.g. destroyed by fire, stolen, accident etc.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>2002>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following countries are members of the Lake Chad Basin Commission?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Niger and Cameroun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Benin and Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chad and Benin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria and Mali</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Lake Chad Basin Commission (LCBC) is a regional organization established in 1964 by Cameroon, Chad, Niger, and Nigeria. Therefore, the correct answer is 'Niger and Cameroun'. The LCBC's mission is to sustainably and equitably manage the Lake Chad and other shared water resources of the Lake Chad Basin, preserve the ecosystems of the Lake Chad Conventional Basin, promote regional integration, peace and security.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>2002>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A core investor in the current phase of privatization in Nigeria is one who</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">can afford to buy most of the shares of the enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">will be at the core of the enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can mobilize foreign currency equivalent to the value of the enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has the technical know-how of the enterprises</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization is a policy designed to enable individuals and private or corporate organisation take over the ownership and control of government business. They also assist individuals to participate in economic activities through ownership of enterprises.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES"}, {"id": "objective>Commerce>2002>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The agency in Nigeria which ensures that products conform to government specifications is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Standard Organization of Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Consumers' Association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturers Association of Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Chambers of Commerce</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Standards Organization of Nigeria ensures that products conform with government standards and specifications.</div>", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : REGULATORY AGENCIES"}, {"id": "objective>Commerce>2002>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Awarding scholarship and sponsoring sports by a business organization are examples of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">advertizing strategy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic responsibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing strategy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">social responsibility</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Awarding scholarships and sponsoring sports by a business organization are examples of social responsibility. Social responsibility refers to the ethical framework in which an entity, be it an organization or individual, has an obligation to act for the benefit of society at large. It is a duty that every individual or organization has to perform so as to maintain a balance between the economy and the ecosystem.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : MEANING AND TYPES"}, {"id": "objective>Commerce>2002>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The commercialization of public enterprise is aimed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing the efficiency and making the enterprise self-sufficient</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertizing and promoting the goods and services of the enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased assistance and patronage of the enterprises by the public</div>", "<div style=\"font-family:Cambria;font-size:17px;\">selling the goods and service of the enterprises</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">commercialisation is a policy geared towards making state-owned enterprises to become more efficient and profit-oriented. The policy makes it possible for public enterprises to become more viable and effective.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVATAGES"}, {"id": "objective>Commerce>2002>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An author's exclusive right to his published works is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">author's right</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constitutional right</div>", "<div style=\"font-family:Cambria;font-size:17px;\">patent right</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copyright</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An author's exclusive right to his published works is known as copyright. Copyright is a legal term used to describe the rights that creators have over their literary and artistic works. Works covered by copyright range from books, music, paintings, sculpture, and films, to computer programs, databases, advertisements, maps, and technical drawings.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>2002>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under the endowment policy, the money handed over to the insured at the expiration of the stipulated time or at death is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">indemnity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surrender value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lump sum benefit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insurance premium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Endowment policy: provides for the sum assured to be paid either after a fixed number of years or at death. <br/> Annuities is a form of pension in which an insurance company, in return for a certain sum of money (paid in lump sum or by installments) agrees to repay plus the investment income</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2002>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The machine used for sending telex messages is known as a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">radar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fax machine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dictaphone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">teleprinter</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The name TELEX is the acronym for TEL egraph EX change service. A Telex Machine, which is a teleprinter can send and receive text based messages using the telegraph service.. A message sent using the Telex machine is known as a Telex message. <br/> A teleprinter (teletypewriter, teletype or TTY) is an electromechanical device that can be used to send and receive typed messages through various communications channels, in both point-to-point and point-to-multipoint configurations.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES"}, {"id": "objective>Commerce>2002>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these insurance principles requires a close connection between the actual loss suffered and the risk insured?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">indemnity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proximate cause</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contribution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subrogation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Proximate cause is the principle that requires a close connection between loss suffered and risk insured.</div>", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES"}, {"id": "objective>Commerce>2002>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The unit through which results of a processed data are displayed is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">logic unit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">display unit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">control unit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">output unit</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The unit through which results of a processed data are displayed is the output unit. The output unit of a computer is responsible for providing the results of processed data to the user in a usable format. This could be in the form of a printed report, visual display on a screen, or even audio output.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2002>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used to inform the addressee that a registered parcel is ready for collection?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">express label</div>", "<div style=\"font-family:Cambria;font-size:17px;\">counterfoil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">telegram</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slip</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A slip is used to inform the addressee that a registered parcel is ready for collection. When a registered parcel arrives at the post office, a slip (also known as a notice of arrival) is sent to the recipient's address to inform them that they have a parcel ready for collection.</div>", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION"}, {"id": "objective>Commerce>2002>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of computer commonly found in offices is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">laptop</div>", "<div style=\"font-family:Cambria;font-size:17px;\">desktop</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the hybrid computer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the mainframe computer</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A desktop computer is a personal computer designed for regular use at a single location on or near a desk due to its size and power requirements.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2002>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mode of transporting crude oil to the ports for export purposes is by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tanker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">road</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pipeline</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Some of the most popular ways of transporting crude oil and gas across the world: <br/> -  Trucks:  The easiest and most utilized form of transportation in the oil and gas industry is trucking. With on-the-road transportation, you can schedule shipments at any time and move them at any place. This advantage makes trucking way more beneficial than other transportation modes. Also, it moves smaller amounts of oil, meaning that the extent of damage in case of cracks or leaks is relatively small. <br/>  <br/> -  Pipelines: <br/> This transportation method suggests that oil is gathered and then transported directly to the site or plant via a pipeline network. Despite pipeline shipping being a hot topic of discussions between industry experts, it is a fast and reliable way to distribute oil. New technology helps advance the safety of this mode, and pipelines have sensors for monitoring important indicators like temperature, pressure, etc. it limits areas and destinations you can ship to because the pipeline infrastructure is not developed enough. Additionally, pipelines move enormous amounts of oil, so when an accident happens, the damage is very serious and it's often hard to liquidate the consequences. <br/>  <br/> -  Ocean:  <br/> Ships are a slow, inexpensive, reliable way to move extremely large volumes of fuel. Ocean transportation has one big advantage over other shipping methods, which is that you can transport materials globally. Despite longer transit, it is the most efficient mode for moving oil across the world. Essentially, ocean shipping is mostly used as a part of a large intermodal strategy. <br/>  <br/> - Rail: <br/> Rail transport was a primary way to move oil for more than 150 years. Rail transportation makes oil containers less prone to damage compared to other shipping modes. This method doesn't have enough flexibility to move oil at any point. But, when combined with other modes, rail can be extremely beneficial for a fairly fast and cost-effective way to move oil long-distance.</div>", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION"}, {"id": "objective>Commerce>2002>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The temporary insurance certificate issued to the insured before drawing up a policy is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cover note</div>", "<div style=\"font-family:Cambria;font-size:17px;\">testimonial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">time policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proposal form</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cover notes is a temporary insurance note (cover) to enable the insured to enjoy the benefits of a policy.</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2002>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The bulls and bears in the Stock Exchange Market help to minimize</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the number of shares and bonds sold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price increases of securities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fluctuation in price of securities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the elasticity of price of securities</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bulls and bears are agent in the stock market and they help in minimizing fluctuation in price of securities.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2002>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Debentures differs from shares in that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they are secured on the company's assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ownership is open to the public</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they form part of the capital of the business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rewards are usually paid out of profit</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Debentures and shares are both ways for a company to raise capital, but they are different in several ways. One of the key differences is that debentures are secured on the company's assets. This means that if the company fails to pay back the debenture, the holder can claim the company's assets as a form of repayment.</div>", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES"}, {"id": "objective>Commerce>2002>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Stock Exchange is a market where</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">long-term securities are sold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all types of securities are sold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">short-term securities are sold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">medium-term securities are sold</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Stock Exchange is a marketplace for buying and selling securities. However, it is primarily associated with the trading of long-term securities such as stocks and bonds. These are investments that are typically held for a period of more than one year. <br/>  <br/> All types of securities are sold is incorrect because the Stock Exchange does not sell all types of securities. For example, it does not sell bonds or other types of debt securities.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2002>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A retail cooperative society aims at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hoarding manufactured goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cutting off the profit of middle men</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lending money to members at low interest rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouraging members to save money</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Retail cooperative society cut off profit of the middlemen by contributing funds to buy in bulk directly from the manufacturers.</div>", "topic": "TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>2002>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bill of exchange already accepted can be discounted by the holder in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">central bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at least two banks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">his bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">any bank</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A bill of exchange is a written order used primarily in international trade that binds one party to pay a fixed sum of money to another party on demand or at a predetermined date. Once it is accepted, it can be discounted by the holder in any bank. Discounting here means the bank buys the bill (which will be paid by the debtor at the due date) and gives the holder the money immediately, but less a discount (interest). Therefore, the correct answer is option 4.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2002>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The document issued by the seller which gives details of the goods is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">catalogue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tender</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price list</div>", "<div style=\"font-family:Cambria;font-size:17px;\">invoice</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Proforma Invoice Document: The seller will send an official Proforma Invoice document to reconfirm the details of the goods to be supplied. Note – Both parties must counter sign the Purchase Order and Proforma Invoice documents. These document represent a legally binding agreement between the buyer and seller.</div>", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING"}, {"id": "objective>Commerce>2002>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given;  <br/> I. Retail  <br/> II. Export  <br/> III. Transport  <br/> IV. Import  <br/> V. Insurance  <br/> VI. Banking and Finance  <br/> VII. Wholesale  <br/> VIII. Communication  <br/> Which of the above are aids to Trade?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and VIII</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III, V, VI and VIII</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, V, VI and VII</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aids to trade are insurance, tourism, banking, transportation, warehousing,advertising and communication.</div>", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA~~AIDS TO TRADE: BANKING : SERVICES & CHALLEGES~~AIDS TO TRADE: COMMUNICATION : TYPES~~AIDS TO TRADE: INSURANCE : TYPES~~AIDS TO TRADE: TOURISM : TYPES & IMPORTANCE~~AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION~~TRADE (1) : HOME TRADE: WHOLESALE TRADE~~TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>2002>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organizational structure that relates the positions of specialists to the line managers is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">line structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">staff structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">line and staff structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">functional structure</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Line and Staff Organization is a modification of the Line Organization. Here, functional specialists work with line managers to guide and advise them.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2002>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A wholesaler who possesses the title to the goods he sells is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a merchant wholesaler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multiple wholesaler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a general wholesaler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an agent wholesaler</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Merchant wholesalers make up 80 percent of all wholesaling establishments and conduct slightly less than 60 percent of all wholesale sales. A merchant wholesaler is an institution that buys goods from manufacturers and resells them to businesses, government agencies, other wholesalers, or retailers.</div>", "topic": "TRADE (1) : HOME TRADE: WHOLESALE TRADE"}, {"id": "objective>Commerce>2002>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important principle of a good organizational structure is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ideal standard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">span of control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clarity of mission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adequacy of resources</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Span of control also known as span of management. It refers to the number of subordinate a manager can effectively control or number of subordinate working with him. Span of control is one of the principle of management propounded by Henry Fayol.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2002>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A company that is registered with the Corporate Affairs Commission only without being enlisted on the Stock Exchange is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public liability company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint venture company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limited company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">registered company</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A company that is registered with the Corporate Affairs Commission only without being enlisted on the Stock Exchange is a registered company. This means that the company has been legally recognized by the government but is not publicly traded on the stock exchange.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES"}, {"id": "objective>Commerce>2002>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A contract for the sale of goods involves the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">producer, seller and the buyer of good</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offering of goods to customers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transfer of the title to goods for money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange of goods</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Contract of sale of goods is a contract, whereby, the seller transfers or agrees to transfer the property in goods to the buyer for a price(money). There can be a contract of sale between one part-owner and another.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>2002>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The total of the share capital which a company could be allowed to issue is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">called-up capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paid up capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nominal capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">issued capital</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A company's share capital is the money it raises from selling common or preferred stock. The maximum amount of share capital a company is allowed to raise is called its authorized capital. This does not limit the number of shares a company may issue but it puts a ceiling on the total amount of money that can be raised by the sale of those shares. <br/> Nominal capital is also known as registered or authorized capital. <br/>  <br/>  <br/> </div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2002>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of mobilizing, engaging and maintaining workers to work for an organization is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">staffing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">selection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recruitment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">employment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Staffing is the process of identifying, selecting, training, and maintaining the workforce in an organization. It involves all the activities related to hiring and retaining the employees. This includes recruitment, selection, training, and development of the employees.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : BUSINESS RESOURCES"}, {"id": "objective>Commerce>2002>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Recognized members of the Stock Exchange who buy and sell securities on their own behalf are known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bulls</div>", "<div style=\"font-family:Cambria;font-size:17px;\">jobbers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brokers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stags</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Jobbers are professional speculators who perform important functions as member of the stock exchange. Jobbers are independent dealer in securities and transact them in his own. They deal only with members of stock exchanges like broker of other jobber and do not interact with a non-member.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2002>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following involved foreign trade?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supermarket</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chain stores</div>", "<div style=\"font-family:Cambria;font-size:17px;\">departmental stores</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commodity markets</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commodity markets are places where commodities, such as wheat, corn, and oil, are traded. These markets are important for foreign trade because they allow traders to buy and sell commodities from different countries.</div>", "topic": "TRADE ( 2) : FOREIGN TRADE"}, {"id": "objective>Commerce>2002>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a function of employers' association?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">undertaking research on behalf of employee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promotion of thrift in workers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promotion of workers welfare</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissemination of information through sponsored journals</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Employers' associations are organizations that represent the interests of employers in negotiations with trade unions. They typically provide services to their members, such as legal advice, training, and lobbying. <br/>  <br/> One of the main functions of employers' associations is to promote the welfare of their members' employees. This includes providing benefits such as health insurance, pensions, and training. They also lobby governments on behalf of their members to improve the working conditions and wages of their employees.</div>", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS"}, {"id": "objective>Commerce>2002>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following industries is normally located near the source of its raw materials?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">foot ware industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cement industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">textile industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">automobile assembly</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cement industry is typically located near the source of its raw materials. This is because the main raw materials used in cement production, such as limestone and clay, are heavy and bulky. Transporting these materials over long distances can significantly increase production costs. Therefore, to minimize transportation costs, cement plants are usually located close to the source of raw materials.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2002>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the most important functions of marketing is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">encouraging research activities to meet needs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">creating classes of merchants among business men</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the extension of markets for businesses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">providing finances to businesses</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marketing is the process of creating, communicating, delivering, and exchanging offerings that have value for customers, clients, partners, and society at large. It includes the activities of: <br/>  <br/> -  Market research: This involves gathering information about customers, competitors, and the market environment. <br/> -   Product development: This involves creating products and services that meet the needs of customers. <br/> -   Pricing: This involves setting prices that are fair to both customers and the company. <br/> -  Distribution: This involves getting products and services to customers. <br/> -   Promotion: This involves communicating the value of products and services to customers. <br/>  <br/> Of all of these activities, market research is the most important because it helps businesses to understand the needs of their customers. By understanding the needs of their customers, businesses can create products and services that meet those needs and are more likely to be successful.</div>", "topic": "ELEMENT OF MARKETING : MEANING AND IMPORTANCE ANF FUNCTIONS"}, {"id": "objective>Commerce>2002>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Securities on which the buyers are not issued with certificates are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">authorized securities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inscribed securities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bearer securities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">registered securities</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inscribed securities are those securities on which the buyers are not issued with certificates. Instead, the owner's name and details of the securities are recorded in the books of the company and receipts are issued to the owner as evidence of ownership. This is different from bearer securities where the certificates are issued to the holder, or registered securities where the owner's name is registered with the issuing company.</div>", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES"}, {"id": "objective>Commerce>2002>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In product pricing, which of these elements needs more consideration than others?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the demand for the product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the demography of the buyers of the product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the economic conditions in the market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the cost of producing the product</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In product pricing, the cost of producing the product needs more consideration than others. While demand, demography of buyers, and economic conditions in the market are important, the cost of production directly impacts the price of the product. If the cost of production is high, the selling price will also be high to ensure profitability. Therefore, the cost of production is a key element in product pricing.</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2002>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principal objectives of the Central Bank of Nigeria can be classified broadly into</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bankers' bank, lender of last resort and issuance of currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">service, currency management and financial intermediation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">banking services, foreign exchange operation and open market operations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">service, monetary policy and developmental functions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major regulatory objectives of the bank as stated in the CBN Act are to: maintain the external reserves of the country, promote monetary stability and a sound financial environment, and to act as a banker of last resort and financial adviser to the federal government.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2002>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The letters E and OE stand for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">errors of exception</div>", "<div style=\"font-family:Cambria;font-size:17px;\">errors and omission expected</div>", "<div style=\"font-family:Cambria;font-size:17px;\">estimated and order error</div>", "<div style=\"font-family:Cambria;font-size:17px;\">end of error</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In business terms, 'E and OE' stands for 'Errors and Omissions Excepted'. This is a way of saying that if there are any mistakes or things left out of the document by accident, the person who wrote it is not legally responsible for them. Therefore, option 2 is the correct answer.</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE"}, {"id": "objective>Commerce>2002>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important issue for consideration in the product element of the marketing mix is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adequate promotion of the product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">channel of distribution of the product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price of the product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">planning and development of the product</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The product is the most important element of the marketing mix. It is the first and starting point of planning in marketing mix.</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2002>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A group of companies is a collection of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">subsidiaries and their holding company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">firms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">associates and their holding company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industries</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A corporate group or group of companies is a collection of parent and subsidiary corporations that function as a single economic entity through a common source of control.</div>", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER"}, {"id": "objective>Commerce>2002>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of trade association?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">European Union</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Marketing Board</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Organization of Africa Union</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Farmers' Council</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A trade association, also known as an industry trade group, business association, sector association or industry body, is an organization founded and funded by businesses that operate in a specific industry. An example of a trade association is the National Farmers' Council, which is an organization that represents the farmers and the agricultural industry.</div>", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS"}, {"id": "objective>Commerce>2002>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following determines the quality of goods that a retailer sells?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The mode of contract of sales</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The type of manufacturer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The regulations regarding sales in the area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The location of the Shop</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A retailer is a business that sells goods to consumers. They typically do not produce the goods themselves, but they buy them from manufacturers and then sell them to consumers. <br/>  <br/> The quality of the goods that a retailer sells depends on the quality of the goods that they buy from the manufacturer. If the manufacturer produces high-quality goods, then the retailer will be able to sell high-quality goods to consumers. If the manufacturer produces low-quality goods, then the retailer will be able to sell low-quality goods to consumers.</div>", "topic": "TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>2002>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of hire purchase to the consumer is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">economies of sales in the area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">possession of goods before payment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in turnover and profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low interest rate chargeable</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hire purchase usually calls for collection of goods before payment. It is a system by which one pays for a thing in regular installments while having the use of it.</div>", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : ADVANTAGES & DISADVANTAGES"}, {"id": "objective>Commerce>2002>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The founders' shares are usually referred to as deferred shares because the holders</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are entitled to cumulative dividends</div>", "<div style=\"font-family:Cambria;font-size:17px;\">receive their dividends after other share holders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">receive their dividends before other share holders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are not entitled to any dividends</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Founders shares are shareholders whose dividend are paid after all other shareholders have been paid.</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}];
